    let circle_in = c2Circle { p: c2V(x, y), r };

    let circle = c2Circle {
        p: c2V(-70.0, 0.0),
        r: 20.0,
    };

    let aabb = c2AABB {
        min: c2V(-40.0, -40.0),
        max: c2V(-15.0, -15.0),
    };

    let capsule = c2Capsule {
        a: c2V(-40.0, 40.0),
        b: c2V(-20.0, 100.0),
        r: 10.0,
    };

    let mut result = 0;
    result += c2Collided(
        (&raw const circle_in).cast::<std::ffi::c_void>(),
        (&raw const circle).cast::<std::ffi::c_void>(),
        C2_TYPE_CIRCLE,
    );
    result += c2Collided(
        (&raw const circle_in).cast::<std::ffi::c_void>(),
        (&raw const aabb).cast::<std::ffi::c_void>(),
        C2_TYPE_AABB,
    ) << 1;
    result += c2Collided(
        (&raw const circle_in).cast::<std::ffi::c_void>(),
        (&raw const capsule).cast::<std::ffi::c_void>(),
        C2_TYPE_CAPSULE,
    ) << 2;

    result
